   102→
   103→#ifndef __MINGW32__
   104→static int
   105→setnonblocking(int fd)
   106→{
   107→    int flags;
   108→    if (-1 == (flags = fcntl(fd, F_GETFL, 0))) {
   109→        flags = 0;
   110→    }
   111→    return fcntl(fd, F_SETFL, flags | O_NONBLOCK);
   112→}
   113→
   114→#endif
   115→
   116→int
   117→create_and_bind(const char *addr, const char *port)
   118→{
   119→    struct addrinfo hints;
   120→    struct addrinfo *result, *rp;
   121→    int s, listen_sock;
   122→
   123→    memset(&hints, 0, sizeof(struct addrinfo));
   124→    hints.ai_family   = AF_UNSPEC;   /* Return IPv4 and IPv6 choices */
   125→    hints.ai_socktype = SOCK_STREAM; /* We want a TCP socket */
   126→
   127→    s = getaddrinfo(addr, port, &hints, &result);
   128→    if (s != 0) {
   129→        LOGI("getaddrinfo: %s", gai_strerror(s));
   130→        return -1;
   131→    }
   132→
   133→    for (rp = result; rp != NULL; rp = rp->ai_next) {
   134→        listen_sock = socket(rp->ai_family, rp->ai_socktype, rp->ai_protocol);
   135→        if (listen_sock == -1) {
   136→            continue;
   137→        }
   138→
   139→        int opt = 1;
   140→        setsockopt(listen_sock, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));
   141→#ifdef SO_NOSIGPIPE
   142→        setsockopt(listen_sock, SOL_SOCKET, SO_NOSIGPIPE, &opt, sizeof(opt));
   143→#endif
   144→        int err = set_reuseport(listen_sock);
   145→        if (err == 0) {
   146→            LOGI("tcp port reuse enabled");
   147→        }
   148→
   149→        s = bind(listen_sock, rp->ai_addr, rp->ai_addrlen);
   150→        if (s == 0) {
   151→            /* We managed to bind successfully! */
   152→            break;
   153→        } else {
   154→            ERROR("bind");
   155→        }
   156→
   157→        close(listen_sock);
   158→    }
   159→
   160→    if (rp == NULL) {
   161→        LOGE("Could not bind");
   162→        return -1;
   163→    }
   164→
   165→    freeaddrinfo(result);
   166→
   167→    return listen_sock;
   168→}
   169→
   170→static void
   171→server_recv_cb(EV_P_ ev_io *w, int revents)
   172→{
   173→    server_ctx_t *server_recv_ctx = (server_ctx_t *)w;
   174→    server_t *server              = server_recv_ctx->server;
   175→    remote_t *remote              = server->remote;
   176→
   177→    if (remote == NULL) {
   178→        close_and_free_server(EV_A_ server);
   179→        return;
   180→    }
   181→
   182→    ssize_t r = recv(server->fd, remote->buf->array, BUF_SIZE, 0);
   183→
   184→    if (r == 0) {
   185→        // connection closed
   186→        close_and_free_remote(EV_A_ remote);
   187→        close_and_free_server(EV_A_ server);
   188→        return;
   189→    } else if (r == -1) {
   190→        if (errno == EAGAIN || errno == EWOULDBLOCK) {
   191→            // no data
   192→            // continue to wait for recv
   193→            return;
   194→        } else {
   195→            ERROR("server recv");
   196→            close_and_free_remote(EV_A_ remote);
   197→            close_and_free_server(EV_A_ server);
   198→            return;
   199→        }
   200→    }
   201→
   202→    remote->buf->len = r;
   203→
   204→    if (auth) {
   205→        ss_gen_hash(remote->buf, &remote->counter, server->e_ctx, BUF_SIZE);
   206→    }
   207→
   208→    int err = ss_encrypt(remote->buf, server->e_ctx, BUF_SIZE);
   209→
   210→    if (err) {
   211→        LOGE("invalid password or cipher");
   212→        close_and_free_remote(EV_A_ remote);
   213→        close_and_free_server(EV_A_ server);
   214→        return;
   215→    }
   216→
   217→    int s = send(remote->fd, remote->buf->array, remote->buf->len, 0);
   218→
   219→    if (s == -1) {
   220→        if (errno == EAGAIN || errno == EWOULDBLOCK) {
   221→            // no data, wait for send
   222→            remote->buf->idx = 0;
   223→            ev_io_stop(EV_A_ & server_recv_ctx->io);
   224→            ev_io_start(EV_A_ & remote->send_ctx->io);
   225→            return;
   226→        } else {
   227→            ERROR("send");
   228→            close_and_free_remote(EV_A_ remote);
   229→            close_and_free_server(EV_A_ server);
   230→            return;
   231→        }
   232→    } else if (s < remote->buf->len) {
   233→        remote->buf->len -= s;
   234→        remote->buf->idx  = s;
   235→        ev_io_stop(EV_A_ & server_recv_ctx->io);
   236→        ev_io_start(EV_A_ & remote->send_ctx->io);
   237→        return;
   238→    }
   239→}
   240→
   241→static void
   242→server_send_cb(EV_P_ ev_io *w, int revents)
   243→{
   244→    server_ctx_t *server_send_ctx = (server_ctx_t *)w;
   245→    server_t *server              = server_send_ctx->server;
   246→    remote_t *remote              = server->remote;
   247→    if (server->buf->len == 0) {
   248→        // close and free
   249→        close_and_free_remote(EV_A_ remote);
   250→        close_and_free_server(EV_A_ server);
   251→        return;
   252→    } else {
   253→        // has data to send
   254→        ssize_t s = send(server->fd, server->buf->array + server->buf->idx,
   255→                         server->buf->len, 0);
   256→        if (s == -1) {
   257→            if (errno != EAGAIN && errno != EWOULDBLOCK) {
   258→                ERROR("send");
   259→                close_and_free_remote(EV_A_ remote);
   260→                close_and_free_server(EV_A_ server);
   261→            }
   262→            return;
   263→        } else if (s < server->buf->len) {
   264→            // partly sent, move memory, wait for the next time to send
   265→            server->buf->len -= s;
   266→            server->buf->idx += s;
   267→            return;
   268→        } else {
   269→            // all sent out, wait for reading
   270→            server->buf->len = 0;
   271→            server->buf->idx = 0;
   272→            ev_io_stop(EV_A_ & server_send_ctx->io);
   273→            if (remote != NULL) {
   274→                ev_io_start(EV_A_ & remote->recv_ctx->io);
   275→            } else {
   276→                close_and_free_remote(EV_A_ remote);
   277→                close_and_free_server(EV_A_ server);
   278→                return;
   279→            }
   280→        }
   281→    }
   282→}
   283→
   284→static void
   285→remote_timeout_cb(EV_P_ ev_timer *watcher, int revents)
   286→{
   287→    remote_ctx_t *remote_ctx
   288→        = cork_container_of(watcher, remote_ctx_t, watcher);
   289→
   290→    remote_t *remote = remote_ctx->remote;
   291→    server_t *server = remote->server;
   292→
   293→    if (verbose) {
   294→        LOGI("TCP connection timeout");
   295→    }
   296→
   297→    ev_timer_stop(EV_A_ watcher);
   298→
   299→    close_and_free_remote(EV_A_ remote);
   300→    close_and_free_server(EV_A_ server);
   301→}
   302→
   303→static void
   304→remote_recv_cb(EV_P_ ev_io *w, int revents)
   305→{
   306→    remote_ctx_t *remote_recv_ctx = (remote_ctx_t *)w;
   307→    remote_t *remote              = remote_recv_ctx->remote;
   308→    server_t *server              = remote->server;
   309→
   310→    ssize_t r = recv(remote->fd, server->buf->array, BUF_SIZE, 0);
   311→
   312→    if (r == 0) {
   313→        // connection closed
   314→        close_and_free_remote(EV_A_ remote);
   315→        close_and_free_server(EV_A_ server);
   316→        return;
   317→    } else if (r == -1) {
   318→        if (errno == EAGAIN || errno == EWOULDBLOCK) {
   319→            // no data
   320→            // continue to wait for recv
   321→            return;
   322→        } else {
   323→            ERROR("remote recv");
   324→            close_and_free_remote(EV_A_ remote);
   325→            close_and_free_server(EV_A_ server);
   326→            return;
   327→        }
   328→    }
   329→
   330→    server->buf->len = r;
   331→
   332→    int err = ss_decrypt(server->buf, server->d_ctx, BUF_SIZE);
   333→
   334→    if (err) {
   335→        LOGE("invalid password or cipher");
   336→        close_and_free_remote(EV_A_ remote);
   337→        close_and_free_server(EV_A_ server);
   338→        return;
   339→    }
   340→
   341→    int s = send(server->fd, server->buf->array, server->buf->len, 0);
   342→
   343→    if (s == -1) {
   344→        if (errno == EAGAIN || errno == EWOULDBLOCK) {
   345→            // no data, wait for send
   346→            server->buf->idx = 0;
   347→            ev_io_stop(EV_A_ & remote_recv_ctx->io);
   348→            ev_io_start(EV_A_ & server->send_ctx->io);
   349→        } else {
   350→            ERROR("send");
   351→            close_and_free_remote(EV_A_ remote);
   352→            close_and_free_server(EV_A_ server);
   353→        }
   354→    } else if (s < server->buf->len) {
   355→        server->buf->len -= s;
   356→        server->buf->idx  = s;
   357→        ev_io_stop(EV_A_ & remote_recv_ctx->io);
   358→        ev_io_start(EV_A_ & server->send_ctx->io);
   359→    }
   360→
   361→    // Disable TCP_NODELAY after the first response are sent
   362→    int opt = 0;
   363→    setsockopt(server->fd, SOL_TCP, TCP_NODELAY, &opt, sizeof(opt));
   364→    setsockopt(remote->fd, SOL_TCP, TCP_NODELAY, &opt, sizeof(opt));
   365→}
   366→
   367→static void
   368→remote_send_cb(EV_P_ ev_io *w, int revents)
   369→{
   370→    remote_ctx_t *remote_send_ctx = (remote_ctx_t *)w;
   371→    remote_t *remote              = remote_send_ctx->remote;
   372→    server_t *server              = remote->server;
   373→
   374→    if (!remote_send_ctx->connected) {
   375→        struct sockaddr_storage addr;
   376→        socklen_t len = sizeof(struct sockaddr_storage);
   377→
   378→        int r = getpeername(remote->fd, (struct sockaddr *)&addr, &len);
   379→        if (r == 0) {
   380→            remote_send_ctx->connected = 1;
   381→            ev_io_stop(EV_A_ & remote_send_ctx->io);
   382→            ev_timer_stop(EV_A_ & remote_send_ctx->watcher);
   383→
   384→            buffer_t ss_addr_to_send;
   385→            buffer_t *abuf = &ss_addr_to_send;
   386→            balloc(abuf, BUF_SIZE);
   387→
   388→            ss_addr_t *sa = &server->destaddr;
   389→            struct cork_ip ip;
   390→            if (cork_ip_init(&ip, sa->host) != -1) {
   391→                if (ip.version == 4) {
   392→                    // send as IPv4
   393→                    struct in_addr host;
   394→                    memset(&host, 0, sizeof(struct in_addr));
   395→                    int host_len = sizeof(struct in_addr);
   396→
   397→                    if (dns_pton(AF_INET, sa->host, &host) == -1) {
   398→                        FATAL("IP parser error");
   399→                    }
   400→                    abuf->array[abuf->len++] = 1;
   401→                    memcpy(abuf->array + abuf->len, &host, host_len);
   402→                    abuf->len += host_len;
   403→                } else if (ip.version == 6) {
   404→                    // send as IPv6
   405→                    struct in6_addr host;
   406→                    memset(&host, 0, sizeof(struct in6_addr));
   407→                    int host_len = sizeof(struct in6_addr);
   408→
   409→                    if (dns_pton(AF_INET6, sa->host, &host) == -1) {
   410→                        FATAL("IP parser error");
   411→                    }
   412→                    abuf->array[abuf->len++] = 4;
   413→                    memcpy(abuf->array + abuf->len, &host, host_len);
   414→                    abuf->len += host_len;
   415→                } else {
   416→                    FATAL("IP parser error");
   417→                }
   418→            } else {
   419→                // send as domain
   420→                int host_len = strlen(sa->host);
   421→
   422→                abuf->array[abuf->len++] = 3;
   423→                abuf->array[abuf->len++] = host_len;
   424→                memcpy(abuf->array + abuf->len, sa->host, host_len);
   425→                abuf->len += host_len;
   426→            }
   427→
   428→            uint16_t port = htons(atoi(sa->port));
   429→            memcpy(abuf->array + abuf->len, &port, 2);
   430→            abuf->len += 2;
   431→
   432→            if (auth) {
   433→                abuf->array[0] |= ONETIMEAUTH_FLAG;
   434→                ss_onetimeauth(abuf, server->e_ctx->evp.iv, BUF_SIZE);
   435→            }
   436→
   437→            int err = ss_encrypt(abuf, server->e_ctx, BUF_SIZE);
   438→            if (err) {
   439→                bfree(abuf);
   440→                LOGE("invalid password or cipher");
   441→                close_and_free_remote(EV_A_ remote);
   442→                close_and_free_server(EV_A_ server);
   443→                return;
   444→            }
   445→
   446→            int s = send(remote->fd, abuf->array, abuf->len, 0);
   447→
   448→            bfree(abuf);
   449→
   450→            if (s < abuf->len) {
   451→                LOGE("failed to send addr");
   452→                close_and_free_remote(EV_A_ remote);
   453→                close_and_free_server(EV_A_ server);
   454→                return;
   455→            }
   456→
   457→            ev_io_start(EV_A_ & remote->recv_ctx->io);
   458→            ev_io_start(EV_A_ & server->recv_ctx->io);
   459→
   460→            return;
   461→        } else {
   462→            ERROR("getpeername");
   463→            // not connected
   464→            close_and_free_remote(EV_A_ remote);
   465→            close_and_free_server(EV_A_ server);
   466→            return;
   467→        }
   468→    } else {
   469→        if (remote->buf->len == 0) {
   470→            // close and free
   471→            close_and_free_remote(EV_A_ remote);
   472→            close_and_free_server(EV_A_ server);
   473→            return;
   474→        } else {
   475→            // has data to send
   476→            ssize_t s = send(remote->fd, remote->buf->array + remote->buf->idx,
   477→                             remote->buf->len, 0);
   478→            if (s == -1) {
   479→                if (errno != EAGAIN && errno != EWOULDBLOCK) {
   480→                    ERROR("send");
   481→                    // close and free
   482→                    close_and_free_remote(EV_A_ remote);
   483→                    close_and_free_server(EV_A_ server);
   484→                }
   485→                return;
   486→            } else if (s < remote->buf->len) {
   487→                // partly sent, move memory, wait for the next time to send
   488→                remote->buf->len -= s;
   489→                remote->buf->idx += s;
   490→                return;
   491→            } else {
   492→                // all sent out, wait for reading
   493→                remote->buf->len = 0;
   494→                remote->buf->idx = 0;
   495→                ev_io_stop(EV_A_ & remote_send_ctx->io);
   496→                ev_io_start(EV_A_ & server->recv_ctx->io);
   497→            }
   498→        }
   499→    }
   500→}
   501→
   502→static remote_t *
   503→new_remote(int fd, int timeout)
   504→{
   505→    remote_t *remote = ss_malloc(sizeof(remote_t));
   506→
   507→    memset(remote, 0, sizeof(remote_t));
   508→
   509→    remote->buf                 = ss_malloc(sizeof(buffer_t));
   510→    remote->recv_ctx            = ss_malloc(sizeof(remote_ctx_t));
   511→    remote->send_ctx            = ss_malloc(sizeof(remote_ctx_t));
   512→    balloc(remote->buf, BUF_SIZE);
   513→    memset(remote->recv_ctx, 0, sizeof(remote_ctx_t));
   514→    memset(remote->send_ctx, 0, sizeof(remote_ctx_t));
   515→    remote->fd                  = fd;
   516→    remote->recv_ctx->remote    = remote;
   517→    remote->recv_ctx->connected = 0;
   518→    remote->send_ctx->remote    = remote;
   519→    remote->send_ctx->connected = 0;
   520→
   521→    ev_io_init(&remote->recv_ctx->io, remote_recv_cb, fd, EV_READ);
   522→    ev_io_init(&remote->send_ctx->io, remote_send_cb, fd, EV_WRITE);
   523→    ev_timer_init(&remote->send_ctx->watcher, remote_timeout_cb,
   524→                  min(MAX_CONNECT_TIMEOUT, timeout), 0);
   525→
   526→    return remote;
   527→}
   528→
   529→static void
   530→free_remote(remote_t *remote)
   531→{
   532→    if (remote != NULL) {
   533→        if (remote->server != NULL) {
   534→            remote->server->remote = NULL;
   535→        }
   536→        if (remote->buf) {
   537→            bfree(remote->buf);
   538→            ss_free(remote->buf);
   539→        }
   540→        ss_free(remote->recv_ctx);
   541→        ss_free(remote->send_ctx);
   542→        ss_free(remote);
   543→    }
   544→}
   545→
   546→static void
   547→close_and_free_remote(EV_P_ remote_t *remote)
   548→{
   549→    if (remote != NULL) {
   550→        ev_timer_stop(EV_A_ & remote->send_ctx->watcher);
   551→        ev_io_stop(EV_A_ & remote->send_ctx->io);
   552→        ev_io_stop(EV_A_ & remote->recv_ctx->io);
   553→        close(remote->fd);
   554→        free_remote(remote);
   555→    }
   556→}
   557→
   558→static server_t *
   559→new_server(int fd, int method)
   560→{
   561→    server_t *server = ss_malloc(sizeof(server_t));
   562→    memset(server, 0, sizeof(server_t));
   563→
   564→    server->buf                 = ss_malloc(sizeof(buffer_t));
   565→    server->recv_ctx            = ss_malloc(sizeof(server_ctx_t));
   566→    server->send_ctx            = ss_malloc(sizeof(server_ctx_t));
   567→    balloc(server->buf, BUF_SIZE);
   568→    memset(server->recv_ctx, 0, sizeof(server_ctx_t));
   569→    memset(server->send_ctx, 0, sizeof(server_ctx_t));
   570→    server->fd                  = fd;
   571→    server->recv_ctx->server    = server;
   572→    server->recv_ctx->connected = 0;
   573→    server->send_ctx->server    = server;
   574→    server->send_ctx->connected = 0;
   575→
   576→    if (method) {
   577→        server->e_ctx = ss_malloc(sizeof(struct enc_ctx));
   578→        server->d_ctx = ss_malloc(sizeof(struct enc_ctx));
   579→        enc_ctx_init(method, server->e_ctx, 1);
   580→        enc_ctx_init(method, server->d_ctx, 0);
   581→    } else {
   582→        server->e_ctx = NULL;
   583→        server->d_ctx = NULL;
   584→    }
   585→
   586→    ev_io_init(&server->recv_ctx->io, server_recv_cb, fd, EV_READ);
   587→    ev_io_init(&server->send_ctx->io, server_send_cb, fd, EV_WRITE);
   588→
   589→    return server;
   590→}
   591→
   592→static void
   593→free_server(server_t *server)
   594→{
   595→    if (server != NULL) {
   596→        if (server->remote != NULL) {
   597→            server->remote->server = NULL;
   598→        }
   599→        if (server->e_ctx != NULL) {
   600→            cipher_context_release(&server->e_ctx->evp);
   601→            ss_free(server->e_ctx);
   602→        }
   603→        if (server->d_ctx != NULL) {
   604→            cipher_context_release(&server->d_ctx->evp);
   605→            ss_free(server->d_ctx);
   606→        }
   607→        if (server->buf) {
   608→            bfree(server->buf);
   609→            ss_free(server->buf);
   610→        }
   611→        ss_free(server->recv_ctx);
   612→        ss_free(server->send_ctx);
   613→        ss_free(server);
   614→    }
   615→}
   616→
   617→static void
   618→close_and_free_server(EV_P_ server_t *server)
   619→{
   620→    if (server != NULL) {
   621→        ev_io_stop(EV_A_ & server->send_ctx->io);
   622→        ev_io_stop(EV_A_ & server->recv_ctx->io);
   623→        close(server->fd);
   624→        free_server(server);
   625→    }
   626→}
   627→
   628→static void
   629→accept_cb(EV_P_ ev_io *w, int revents)
   630→{
   631→    struct listen_ctx *listener = (struct listen_ctx *)w;
   632→    int serverfd                = accept(listener->fd, NULL, NULL);
   633→    if (serverfd == -1) {
   634→        ERROR("accept");
   635→        return;
   636→    }
   637→    setnonblocking(serverfd);
   638→    int opt = 1;
   639→    setsockopt(serverfd, SOL_TCP, TCP_NODELAY, &opt, sizeof(opt));
   640→#ifdef SO_NOSIGPIPE
   641→    setsockopt(serverfd, SOL_SOCKET, SO_NOSIGPIPE, &opt, sizeof(opt));
   642→#endif
   643→
   644→    int index                    = rand() % listener->remote_num;
   645→    struct sockaddr *remote_addr = listener->remote_addr[index];
   646→
   647→    int remotefd = socket(remote_addr->sa_family, SOCK_STREAM, IPPROTO_TCP);
   648→    if (remotefd == -1) {
   649→        ERROR("socket");
   650→        return;
   651→    }
   652→
   653→#ifdef ANDROID
   654→    if (vpn) {
   655→        int not_protect = 0;
   656→        if (remote_addr->sa_family == AF_INET) {
   657→            struct sockaddr_in *s = (struct sockaddr_in *)remote_addr;
   658→            if (s->sin_addr.s_addr == inet_addr("127.0.0.1"))
   659→                not_protect = 1;
   660→        }
   661→        if (!not_protect) {
   662→            if (protect_socket(remotefd) == -1) {
   663→                ERROR("protect_socket");
   664→                close(remotefd);
   665→                return;
   666→            }
   667→        }
   668→    }
   669→#endif
   670→
   671→    setsockopt(remotefd, SOL_TCP, TCP_NODELAY, &opt, sizeof(opt));
   672→#ifdef SO_NOSIGPIPE
   673→    setsockopt(remotefd, SOL_SOCKET, SO_NOSIGPIPE, &opt, sizeof(opt));
   674→#endif
   675→
   676→    if (listener->mptcp == 1) {
   677→        int err = setsockopt(remotefd, SOL_TCP, MPTCP_ENABLED, &opt, sizeof(opt));
   678→        if (err == -1) {
   679→            ERROR("failed to enable multipath TCP");
   680→        }
   681→    }
   682→
   683→    // Setup
   684→    setnonblocking(remotefd);
   685→#ifdef SET_INTERFACE
   686→    if (listener->iface) {
   687→        if (setinterface(remotefd, listener->iface) == -1)
   688→            ERROR("setinterface");
   689→    }
   690→#endif
   691→
   692→    server_t *server = new_server(serverfd, listener->method);
   693→    remote_t *remote = new_remote(remotefd, listener->timeout);
   694→    server->destaddr = listener->tunnel_addr;
   695→    server->remote   = remote;
   696→    remote->server   = server;
   697→
   698→    int r = connect(remotefd, remote_addr, get_sockaddr_len(remote_addr));
   699→
   700→    if (r == -1 && errno != CONNECT_IN_PROGRESS) {
   701→        ERROR("connect");
   702→        close_and_free_remote(EV_A_ remote);
   703→        close_and_free_server(EV_A_ server);
   704→        return;
   705→    }
   706→
   707→    // listen to remote connected event
   708→    ev_io_start(EV_A_ & remote->send_ctx->io);
   709→    ev_timer_start(EV_A_ & remote->send_ctx->watcher);
   710→}
   711→
   712→void
   713→signal_cb(int dummy)
   714→{
   715→    keep_resolving = 0;
   716→    exit(-1);
   717→}
   718→
   719→int
   720→main(int argc, char **argv)
   721→{
   722→    srand(time(NULL));
   723→
   724→    int i, c;
   725→    int pid_flags    = 0;
   726→    int mptcp        = 0;
   727→    int mtu          = 0;
   728→    char *user       = NULL;
   729→    char *local_port = NULL;
   730→    char *local_addr = NULL;
   731→    char *password   = NULL;
   732→    char *timeout    = NULL;
   733→    char *method     = NULL;
   734→    char *pid_path   = NULL;
   735→    char *conf_path  = NULL;
   736→    char *iface      = NULL;
   737→
   738→    int remote_num = 0;
   739→    ss_addr_t remote_addr[MAX_REMOTE_NUM];
   740→    char *remote_port = NULL;
   741→
   742→    ss_addr_t tunnel_addr = { .host = NULL, .port = NULL };
   743→    char *tunnel_addr_str = NULL;
   744→
   745→    int option_index                    = 0;
   746→    static struct option long_options[] = {
   747→        { "mtu",   required_argument, 0, 0 },
   748→        { "mptcp", no_argument,       0, 0 },
   749→        { "help",  no_argument,       0, 0 },
   750→        {       0,                 0, 0, 0 }
   751→    };
   752→
   753→    opterr = 0;
   754→
   755→    USE_TTY();
   756→
   757→#ifdef ANDROID
   758→    while ((c = getopt_long(argc, argv, "f:s:p:l:k:t:m:i:c:b:L:a:n:P:huUvVA6",
   759→                            long_options, &option_index)) != -1) {
   760→#else
   761→    while ((c = getopt_long(argc, argv, "f:s:p:l:k:t:m:i:c:b:L:a:n:huUvA6",
   762→                            long_options, &option_index)) != -1) {
   763→#endif
   764→        switch (c) {
   765→        case 0:
   766→            if (option_index == 0) {
   767→                mtu = atoi(optarg);
   768→                LOGI("set MTU to %d", mtu);
   769→            } else if (option_index == 1) {
   770→                mptcp = 1;
   771→                LOGI("enable multipath TCP");
   772→            } else if (option_index == 2) {
   773→                usage();
   774→                exit(EXIT_SUCCESS);
   775→            }
   776→            break;
   777→        case 's':
   778→            if (remote_num < MAX_REMOTE_NUM) {
   779→                remote_addr[remote_num].host   = optarg;
   780→                remote_addr[remote_num++].port = NULL;
   781→            }
   782→            break;
   783→        case 'p':
   784→            remote_port = optarg;
   785→            break;
   786→        case 'l':
   787→            local_port = optarg;
   788→            break;
   789→        case 'k':
   790→            password = optarg;
   791→            break;
   792→        case 'f':
   793→            pid_flags = 1;
   794→            pid_path  = optarg;
   795→            break;
   796→        case 't':
   797→            timeout = optarg;
   798→            break;
   799→        case 'm':
   800→            method = optarg;
   801→            break;
   802→        case 'c':
   803→            conf_path = optarg;
   804→            break;
   805→        case 'i':
   806→            iface = optarg;
   807→            break;
   808→        case 'b':
   809→            local_addr = optarg;
   810→            break;
   811→        case 'u':
   812→            mode = TCP_AND_UDP;
   813→            break;
   814→        case 'U':
   815→            mode = UDP_ONLY;
   816→            break;
   817→        case 'L':
   818→            tunnel_addr_str = optarg;
   819→            break;
   820→        case 'a':
   821→            user = optarg;
   822→            break;
   823→#ifdef HAVE_SETRLIMIT
   824→        case 'n':
   825→            nofile = atoi(optarg);
   826→            break;
   827→#endif
   828→        case 'v':
   829→            verbose = 1;
   830→            break;
   831→        case 'h':
   832→            usage();
   833→            exit(EXIT_SUCCESS);
   834→        case 'A':
   835→            auth = 1;
   836→            break;
   837→        case '6':
   838→            ipv6first = 1;
   839→            break;
   840→#ifdef ANDROID
   841→        case 'V':
   842→            vpn = 1;
   843→            break;
   844→        case 'P':
   845→            prefix = optarg;
   846→            break;
   847→#endif
   848→        case '?':
   849→            // The option character is not recognized.
   850→            LOGE("Unrecognized option: %s", optarg);
   851→            opterr = 1;
   852→            break;
   853→        }
   854→    }
   855→
   856→    if (opterr) {
   857→        usage();
   858→        exit(EXIT_FAILURE);
   859→    }
   860→
   861→    if (argc == 1) {
   862→        if (conf_path == NULL) {
   863→            conf_path = DEFAULT_CONF_PATH;
   864→        }
   865→    }
   866→
   867→    if (conf_path != NULL) {
   868→        jconf_t *conf = read_jconf(conf_path);
   869→        if (remote_num == 0) {
   870→            remote_num = conf->remote_num;
   871→            for (i = 0; i < remote_num; i++)
   872→                remote_addr[i] = conf->remote_addr[i];
   873→        }
   874→        if (remote_port == NULL) {
   875→            remote_port = conf->remote_port;
   876→        }
   877→        if (local_addr == NULL) {
   878→            local_addr = conf->local_addr;
   879→        }
   880→        if (local_port == NULL) {
   881→            local_port = conf->local_port;
   882→        }
   883→        if (password == NULL) {
   884→            password = conf->password;
   885→        }
   886→        if (method == NULL) {
   887→            method = conf->method;
   888→        }
   889→        if (timeout == NULL) {
   890→            timeout = conf->timeout;
   891→        }
   892→        if (user == NULL) {
   893→            user = conf->user;
   894→        }
   895→        if (auth == 0) {
   896→            auth = conf->auth;
   897→        }
   898→        if (tunnel_addr_str == NULL) {
   899→            tunnel_addr_str = conf->tunnel_address;
   900→        }
   901→        if (mode == TCP_ONLY) {
   902→            mode = conf->mode;
   903→        }
   904→        if (mtu == 0) {
   905→            mtu = conf->mtu;
   906→        }
   907→        if (mptcp == 0) {
   908→            mptcp = conf->mptcp;
   909→        }
   910→#ifdef HAVE_SETRLIMIT
   911→        if (nofile == 0) {
   912→            nofile = conf->nofile;
   913→        }
   914→#endif
   915→    }
   916→
   917→    if (remote_num == 0 || remote_port == NULL || tunnel_addr_str == NULL ||
   918→        local_port == NULL || password == NULL) {
   919→        usage();
   920→        exit(EXIT_FAILURE);
   921→    }
   922→
   923→    if (method == NULL) {
   924→        method = "rc4-md5";
   925→    }
   926→
   927→    if (timeout == NULL) {
   928→        timeout = "60";
   929→    }
   930→
   931→#ifdef HAVE_SETRLIMIT
   932→    /*
   933→     * no need to check the return value here since we will show
   934→     * the user an error message if setrlimit(2) fails
   935→     */
   936→    if (nofile > 1024) {
   937→        if (verbose) {
   938→            LOGI("setting NOFILE to %d", nofile);
   939→        }
   940→        set_nofile(nofile);
   941→    }
   942→#endif
   943→
   944→    if (local_addr == NULL) {
   945→        local_addr = "127.0.0.1";
   946→    }
   947→
   948→    if (pid_flags) {
   949→        USE_SYSLOG(argv[0]);
   950→        daemonize(pid_path);
   951→    }
   952→
   953→    if (ipv6first) {
   954→        LOGI("resolving hostname to IPv6 address first");
   955→    }
   956→
   957→    if (auth) {
   958→        LOGI("onetime authentication enabled");
   959→    }
   960→
   961→    // parse tunnel addr
   962→    parse_addr(tunnel_addr_str, &tunnel_addr);
   963→
   964→    if (tunnel_addr.port == NULL) {
   965→        FATAL("tunnel port is not defined");
   966→    }
   967→
   968→#ifdef __MINGW32__
   969→    winsock_init();
   970→#else
   971→    // ignore SIGPIPE
   972→    signal(SIGPIPE, SIG_IGN);
   973→    signal(SIGABRT, SIG_IGN);
   974→    signal(SIGINT, signal_cb);
   975→    signal(SIGTERM, signal_cb);
   976→#endif
   977→
   978→    // Setup keys
   979→    LOGI("initializing ciphers... %s", method);
   980→    int m = enc_init(password, method);
   981→
   982→    // Setup proxy context
   983→    struct listen_ctx listen_ctx;
   984→    memset(&listen_ctx, 0, sizeof(struct listen_ctx));
   985→    listen_ctx.tunnel_addr = tunnel_addr;
   986→    listen_ctx.remote_num  = remote_num;
   987→    listen_ctx.remote_addr = ss_malloc(sizeof(struct sockaddr *) * remote_num);
   988→    memset(listen_ctx.remote_addr, 0, sizeof(struct sockaddr *) * remote_num);
   989→    for (i = 0; i < remote_num; i++) {
   990→        char *host = remote_addr[i].host;
   991→        char *port = remote_addr[i].port == NULL ? remote_port :
   992→                     remote_addr[i].port;
   993→        struct sockaddr_storage *storage = ss_malloc(sizeof(struct sockaddr_storage));
   994→        memset(storage, 0, sizeof(struct sockaddr_storage));
   995→        if (get_sockaddr(host, port, storage, 1, ipv6first) == -1) {
   996→            FATAL("failed to resolve the provided hostname");
   997→        }
   998→        listen_ctx.remote_addr[i] = (struct sockaddr *)storage;
   999→    }
  1000→    listen_ctx.timeout = atoi(timeout);
  1001→    listen_ctx.iface   = iface;
  1002→    listen_ctx.method  = m;
  1003→    listen_ctx.mptcp   = mptcp;
  1004→
  1005→    struct ev_loop *loop = EV_DEFAULT;
  1006→
  1007→    if (mode != UDP_ONLY) {
  1008→        // Setup socket
  1009→        int listenfd;
  1010→        listenfd = create_and_bind(local_addr, local_port);
  1011→        if (listenfd == -1) {
  1012→            FATAL("bind() error:");
  1013→        }
  1014→        if (listen(listenfd, SOMAXCONN) == -1) {
  1015→            FATAL("listen() error:");
  1016→        }
  1017→        setnonblocking(listenfd);
  1018→
  1019→        listen_ctx.fd = listenfd;
  1020→
  1021→        ev_io_init(&listen_ctx.io, accept_cb, listenfd, EV_READ);
  1022→        ev_io_start(loop, &listen_ctx.io);
  1023→    }
  1024→
  1025→    // Setup UDP
  1026→    if (mode != TCP_ONLY) {
  1027→        LOGI("UDP relay enabled");
  1028→        init_udprelay(local_addr, local_port, listen_ctx.remote_addr[0],
  1029→                      get_sockaddr_len(listen_ctx.remote_addr[0]),
  1030→                      tunnel_addr, mtu, m, auth, listen_ctx.timeout, iface);
  1031→    }
  1032→
  1033→    if (mode == UDP_ONLY) {
  1034→        LOGI("TCP relay disabled");
  1035→    }
  1036→
  1037→    LOGI("listening at %s:%s", local_addr, local_port);
  1038→
  1039→    // setuid
  1040→    if (user != NULL && ! run_as(user)) {
  1041→        FATAL("failed to switch user");
  1042→    }
  1043→
  1044→#ifndef __MINGW32__
  1045→    if (geteuid() == 0){
  1046→        LOGI("running from root user");
  1047→    }
  1048→#endif
  1049→
  1050→    ev_run(loop, 0);
  1051→
  1052→#ifdef __MINGW32__
  1053→    winsock_cleanup();
  1054→#endif
  1055→
  1056→    return 0;
  1057→}
